# ─── Config ───────────────────────────────────────────────────────────────────
USERS_FILE = Path("users.json")
META_FILE  = Path("videos_meta.json")
SECRET_KEY = os.environ.get("SECRET_KEY", "nyztrade-secret-2024")

# ─── Auth helpers ─────────────────────────────────────────────────────────────
def load_users():
    if USERS_FILE.exists():
        with open(USERS_FILE) as f:
            return json.load(f)
    default = {
        "admin":    {"password_hash": hashlib.sha256(b"admin123").hexdigest(),
                     "role": "admin",   "name": "Admin",            "email": "admin@nyztrade.com"},
        "premium1": {"password_hash": hashlib.sha256(b"premium123").hexdigest(),
                     "role": "premium", "name": "Premium Client 1", "email": "client1@example.com"},
    }
    with open(USERS_FILE, "w") as f:
        json.dump(default, f, indent=2)
    return default

def save_users(users):
    with open(USERS_FILE, "w") as f:
        json.dump(users, f, indent=2)

def verify_password(username, password, users):
    if username not in users:
        return False
    return hmac.compare_digest(
        hashlib.sha256(password.encode()).hexdigest(),
        users[username]["password_hash"])

# ─── Video metadata ───────────────────────────────────────────────────────────
def get_video_list():
    if META_FILE.exists():
        with open(META_FILE) as f:
            return json.load(f)
    return {}

def save_video_meta(meta):
    with open(META_FILE, "w") as f:
        json.dump(meta, f, indent=2)

def img_to_b64(data: bytes, mime: str = "image/jpeg") -> str:
    return f"data:{mime};base64," + base64.b64encode(data).decode()

# ─── VEED embed player with watermark overlay ─────────────────────────────────
def render_protected_video(embed_code: str, watermark_text: str):
    ts    = datetime.now().strftime("%d %b %Y %H:%M")
    clean = re.sub(r'width=["\'][^"\']*["\']',  'width="100%"',  embed_code.strip())
    clean = re.sub(r'height=["\'][^"\']*["\']', 'height="100%"', clean)
    html = (
        "<div class=\'nyz-bar nyz-top\'>"
        "<span style=\'color:#64748b;font-size:0.68rem;\'>&#128274; Protected Stream &middot; VEED.io</span>"
        "<span style=\'color:#f59e0b;font-size:0.68rem;font-family:Rajdhani,sans-serif;\'>"
        + watermark_text + " | " + ts + "</span></div>"
        "<div class=\'nyz-wrap\'>"
        "<div class=\'nyz-wm\'>" + watermark_text + "</div>"
        + clean +
        "</div>"
        "<div class=\'nyz-bar nyz-bot\'>"
        "&#169; NYZTrade Analytics Pvt. Ltd. &nbsp;|&nbsp; Unauthorised recording is prohibited"
        "</div>"
        "<script>"
        "document.addEventListener(\'keyup\',function(e){"
        "if(e.key===\'PrintScreen\'){"
        "var w=document.querySelector(\'.nyz-wrap\');"
        "if(w){w.style.filter=\'blur(20px)\';setTimeout(function(){w.style.filter=\'none\';},3000);}}"
        "});"
        "</script>"
    )
    st.components.v1.html(html, height=520, scrolling=False)

# ─── Shared UI ────────────────────────────────────────────────────────────────
def render_header():
    role  = st.session_state.get("role", "")
    name  = st.session_state.get("name", "")
    badge = "\U0001f6e1\ufe0f ADMIN" if role == "admin" else "\u2b50 PREMIUM"
    st.markdown(
        '<div class="nyz-header">' +
        '<img src="data:image/jpeg;base64,' + LOGO_B64 + '" alt="NYZTrade" />' +
        '<div class="nyz-header-right">' +
        '<div class="nyz-user-badge">' + badge + " &middot; " + name + '</div>' +
        '</div></div>',
        unsafe_allow_html=True)

# ─── Login screen ─────────────────────────────────────────────────────────────
def login_screen(users):
    st.markdown(STYLE, unsafe_allow_html=True)
    _, col, _ = st.columns([1, 3, 1])
    with col:
        st.markdown(
            '<div class="login-card">' +
            '<div class="login-logo">' +
            '<img src="data:image/jpeg;base64,' + LOGO_B64 + '" alt="NYZTrade" />' +
            '<p class="login-tagline">Premium Content Platform</p>' +
            '</div></div>',
            unsafe_allow_html=True)
        with st.form("login_form"):
            username = st.text_input("Username", placeholder="Enter your username")
            password = st.text_input("Password", type="password", placeholder="Enter your password")
            ok = st.form_submit_button("\U0001f510  Login to Premium", use_container_width=True)
        if ok:
            if verify_password(username, password, users):
                st.session_state.update({
                    "authenticated": True, "username": username,
                    "role": users[username]["role"], "name": users[username]["name"],
                    "session_id": str(uuid.uuid4())[:8].upper(),
                })
                st.rerun()
            else:
                st.error("\u274c Invalid credentials. Please contact support.")
        st.markdown(
            '<p style="text-align:center;color:#334155;font-size:0.72rem;margin-top:1rem;">' +
            "\U0001f512 Secure &amp; Protected &nbsp;|&nbsp; &copy; NYZTrade Analytics Pvt. Ltd., Kerala" +
            '</p>',
            unsafe_allow_html=True)

# ─── Admin panel ──────────────────────────────────────────────────────────────
def admin_panel(users):
    tab1, tab2, tab3 = st.tabs([
        "\U0001f4e4  Add Video",
        "\U0001f3ac  Manage Videos",
        "\U0001f465  Users",
    ])

    # ── Tab 1: Add video ──────────────────────────────────────────────────────
    with tab1:
        st.markdown('<div class="section-title">Add Video via VEED.io Embed</div>', unsafe_allow_html=True)
        st.info(
            "\U0001f4cb **How to get embed code from VEED.io:**  \n"
            "Open your video \u2192 **Share** \u2192 **Embed** \u2192 Copy the `<iframe ...>` code \u2192 Paste below."
        )

        title       = st.text_input("Video Title *", placeholder="e.g. Options Greeks Masterclass \u2013 Module 1")
        description = st.text_area("Description (optional)", placeholder="Brief description...", height=70)

        # Desktop: 2 columns; stacks naturally on mobile
        col1, col2 = st.columns([1, 1])
        with col1:
            category = st.selectbox("Category", [
                "Options Trading", "Stock Analysis", "Technical Analysis",
                "Fundamental Analysis", "ESG Investing", "General",
            ])
        with col2:
            st.markdown("**Thumbnail Image**")
            thumb_file = st.file_uploader(
                "Upload thumbnail (JPG / PNG / WebP)",
                type=["jpg", "jpeg", "png", "webp"],
                key="thumb_upload",
                help="Recommended: 16:9 aspect ratio, min 640×360 px"
            )
            if thumb_file:
                st.image(thumb_file, caption="Preview", use_container_width=True)

        embed_code = st.text_area(
            "VEED.io Embed Code *",
            placeholder='<iframe src="https://www.veed.io/embed/..." width="744" height="504" frameborder="0" title="..." allowfullscreen></iframe>',
            height=120,
        )
        if embed_code.strip():
            with st.expander("\U0001f441\ufe0f  Live preview", expanded=True):
                st.components.v1.html(embed_code.strip(), height=340, scrolling=False)

        st.divider()
        can_save = bool(title.strip() and embed_code.strip())
        if not can_save:
            st.caption("\u26a0\ufe0f  Fill in **Video Title** and **Embed Code** to save.")

        if st.button("\U0001f4be  Save Video", type="primary", use_container_width=True, disabled=not can_save):
            # Process thumbnail
            thumb_b64 = ""
            if thumb_file:
                raw   = thumb_file.read()
                ext   = thumb_file.name.rsplit(".", 1)[-1].lower()
                mime  = {"jpg": "image/jpeg", "jpeg": "image/jpeg",
                         "png": "image/png",  "webp": "image/webp"}.get(ext, "image/jpeg")
                thumb_b64 = img_to_b64(raw, mime)

            vid_id = str(uuid.uuid4())[:12]
            meta   = get_video_list()
            meta[vid_id] = {
                "title":        title.strip(),
                "description":  description.strip(),
                "category":     category,
                "embed_code":   embed_code.strip(),
                "thumb_b64":    thumb_b64,          # base64 data-URI
                "uploaded_at":  datetime.now().isoformat(),
                "uploader":     st.session_state["username"],
            }
            save_video_meta(meta)
            st.success("\u2705 \u2018" + title.strip() + "\u2019 saved!")
            st.balloons()

    # ── Tab 2: Manage videos ──────────────────────────────────────────────────
    with tab2:
        st.markdown('<div class="section-title">Manage Videos</div>', unsafe_allow_html=True)
        meta = get_video_list()
        if not meta:
            st.info("No videos added yet. Use \u2018Add Video\u2019 to get started.")
        else:
            for vid_id, info in list(meta.items()):
                with st.expander("\U0001f3ac  " + info["title"] + "  \u00b7  " + info["category"]):
                    ca, cb = st.columns([1, 2])
                    with ca:
                        tb = info.get("thumb_b64", "").strip()
                        if tb:
                            st.markdown(
                                '<img src="' + tb + '" style="width:100%;border-radius:8px;" />',
                                unsafe_allow_html=True)
                        else:
                            st.markdown(
                                '<div style="height:80px;background:#0a1526;border-radius:8px;' +
                                'display:flex;align-items:center;justify-content:center;color:#f59e0b;font-size:2rem;">\u25b6</div>',
                                unsafe_allow_html=True)
                    with cb:
                        st.write("**Added:** " + info["uploaded_at"][:10] +
                                 "  **By:** " + info.get("uploader", "admin"))
                        if info.get("description"):
                            st.caption(info["description"])
                        ec = info.get("embed_code", "")
                        st.code(ec[:80] + ("..." if len(ec) > 80 else ""), language=None)

                    # Thumbnail re-upload inside expander
                    st.markdown("**Update Thumbnail**")
                    new_thumb = st.file_uploader(
                        "Replace thumbnail (JPG/PNG/WebP)",
                        type=["jpg","jpeg","png","webp"],
                        key="rethumb_" + vid_id
                    )
                    col_save, col_del = st.columns(2)
                    with col_save:
                        if new_thumb and st.button("\U0001f5bc\ufe0f  Save thumbnail", key="savethumb_" + vid_id):
                            raw  = new_thumb.read()
                            ext  = new_thumb.name.rsplit(".", 1)[-1].lower()
                            mime = {"jpg":"image/jpeg","jpeg":"image/jpeg",
                                    "png":"image/png","webp":"image/webp"}.get(ext,"image/jpeg")
                            meta[vid_id]["thumb_b64"] = img_to_b64(raw, mime)
                            save_video_meta(meta)
                            st.success("Thumbnail updated!")
                            st.rerun()
                    with col_del:
                        if st.button("\U0001f5d1\ufe0f  Delete video", key="del_" + vid_id, type="secondary"):
                            del meta[vid_id]
                            save_video_meta(meta)
                            st.rerun()

    # ── Tab 3: Users ──────────────────────────────────────────────────────────
    with tab3:
        st.markdown('<div class="section-title">Current Users</div>', unsafe_allow_html=True)
        for uname, uinfo in users.items():
            c1, c2, c3 = st.columns([2, 1, 2])
            c1.write("**" + uname + "** (" + uinfo.get("name", "") + ")")
            c2.write("`" + uinfo["role"] + "`")
            c3.write(uinfo.get("email", ""))
        st.divider()
        st.markdown('<div class="section-title">Add Premium Client</div>', unsafe_allow_html=True)
        with st.form("add_user_form"):
            c1, c2 = st.columns(2)
            nu = c1.text_input("Username")
            np = c2.text_input("Password", type="password")
            c3, c4 = st.columns(2)
            nn = c3.text_input("Full Name")
            ne = c4.text_input("Email")
            nr = st.selectbox("Role", ["premium", "admin"])
            if st.form_submit_button("\u2795  Add User", use_container_width=True):
                if nu in users:
                    st.error("Username already exists.")
                elif nu and np:
                    users[nu] = {
                        "password_hash": hashlib.sha256(np.encode()).hexdigest(),
                        "role": nr, "name": nn, "email": ne,
                    }
                    save_users(users)
                    st.success("\u2705 User \u2018" + nu + "\u2019 added.")
                    st.rerun()
                else:
                    st.warning("Username and password are required.")

# ─── Client view ──────────────────────────────────────────────────────────────
def client_view():
    meta       = get_video_list()
    username   = st.session_state["username"]
    session_id = st.session_state.get("session_id", "DEMO")
    watermark  = "NYZTrade | " + username.upper() + " | " + session_id

    # ── Category filter ──
    categories   = sorted({v["category"] for v in meta.values()}) if meta else []
    selected_cat = st.selectbox("\U0001f4c2  Filter by Category", ["All"] + categories)
    filtered = {k: v for k, v in meta.items()
                if selected_cat == "All" or v["category"] == selected_cat}

    if not filtered:
        st.markdown(
            '<div style="text-align:center;padding:4rem 1rem;color:#334155;">' +
            "\U0001f3ac<br>No videos in this category yet. Check back soon!</div>",
            unsafe_allow_html=True)
        return

    # ── Responsive card grid via CSS grid (HTML) ──────────────────────────────
    cards_html = '<div class="vid-grid">'
    for vid_id, info in filtered.items():
        tb = info.get("thumb_b64", "").strip()
        if tb:
            thumb_html = '<img class="vid-thumb" src="' + tb + '" alt="thumb" loading="lazy" />' 
        else:
            thumb_html = '<div class="vid-thumb-placeholder">\u25b6</div>'
        cards_html += (
            '<div class="vid-card" id="card_' + vid_id + '">' +
            thumb_html +
            '<div class="vid-card-inner">' +
            '<div class="vid-title">' + info["title"] + '</div>' +
            '<div class="cat-pill">' + info["category"] + '</div>' +
            '<div class="vid-meta">' + info["uploaded_at"][:10] + '</div>' +
            '</div></div>'
        )
    cards_html += '</div>'
    st.markdown(cards_html, unsafe_allow_html=True)

    # ── One Watch button per card (Streamlit interactivity) ──
    st.markdown('<div style="height:0.5rem"></div>', unsafe_allow_html=True)
    ncols = min(4, len(filtered))
    cols  = st.columns(ncols)
    for i, (vid_id, info) in enumerate(filtered.items()):
        with cols[i % ncols]:
            if st.button("\u25b6\ufe0f  " + info["title"][:22] + ("\u2026" if len(info["title"]) > 22 else ""),
                         key="watch_" + vid_id, use_container_width=True):
                st.session_state["active_video"] = vid_id
                st.rerun()

    # ── Active player ────────────────────────────────────────────────────────
    if "active_video" in st.session_state:
        vid_id = st.session_state["active_video"]
        if vid_id not in meta:
            del st.session_state["active_video"]
            st.rerun()
            return
        info = meta[vid_id]
        st.divider()

        # Desktop: title left, close right; mobile: stacked
        ct, cx = st.columns([5, 1])
        with ct:
            st.markdown(
                '<div class="player-title">' + info["title"] + '</div>' +
                '<div class="player-meta">' + info["category"] +
                " &middot; " + info["uploaded_at"][:10] + '</div>',
                unsafe_allow_html=True)
        with cx:
            if st.button("\u2716\ufe0f  Close", key="close_player", use_container_width=True):
                del st.session_state["active_video"]
                st.rerun()

        embed = info.get("embed_code", "").strip()
        if embed:
            render_protected_video(embed, watermark)
        else:
            st.error("\u26a0\ufe0f No embed code. Please contact admin.")

        # Description below player
        if info.get("description"):
            st.markdown(
                '<p style="color:#64748b;font-size:0.85rem;margin-top:0.75rem;line-height:1.6;">' +
                info["description"] + '</p>',
                unsafe_allow_html=True)

# ─── Main ─────────────────────────────────────────────────────────────────────
def main():
    users = load_users()
    st.markdown(STYLE, unsafe_allow_html=True)

    if not st.session_state.get("authenticated"):
        login_screen(users)
        return

    render_header()

    # Logout button — top right on desktop, below header on mobile
    _, col_out = st.columns([8, 2])
    with col_out:
        if st.button("\U0001f6aa  Logout", use_container_width=True):
            for k in ["authenticated","username","role","name","session_id","active_video"]:
                st.session_state.pop(k, None)
            st.rerun()

    if st.session_state["role"] == "admin":
        st.markdown('<div class="section-title">\U0001f6e0\ufe0f  Admin Panel</div>', unsafe_allow_html=True)
        admin_panel(users)
    else:
        client_view()

    # Persistent watermark overlay
    st.markdown(
        '<div class="wm-overlay">NYZTrade | ' +
        st.session_state.get("username", "").upper() +
        " | " + st.session_state.get("session_id", "") + '</div>',
        unsafe_allow_html=True)

if __name__ == "__main__":
    main()
